  "plan": "Create and compile a tiny C encoder using the corrected `encode_integer`: stop bits at `tmp + ctx*99`, payload bits at `ctx`. Encode a known string with only literals, run it through /app/decomp, and verify byte-for-byte with cmp. If this passes, I will apply the same fix to the full encoder and regenerate/verify data.comp.",
  "commands": [
    {
      "keystrokes": "cat > /tmp/enc_tiny.c <<'C'
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define RADIX 255
#define INTOFF 9
#define LITSIZE 4

static long range = 1, fraction = 0;
static int cc[2000000];

static void emit_digit(int d){ putchar((unsigned char)((d+1)&0xFF)); }
static void normalize(void){ while(range<RADIX){ long d=fraction/RADIX; fraction=(fraction-d*RADIX)*RADIX; range*=RADIX; emit_digit((int)d); } }
static void put_bit(int ctx,int bit){ normalize(); int idx=ctx*2; int c0=cc[idx], c1=cc[idx+1]; long split=range*(c0+1)/(c0+c1+2); if(bit==0) range=split; else { fraction+=split; range-=split; } cc[idx+bit]++; }
static void encode_integer(int start,int ctx,int value){
    long result=(long)value+(1L<<start);
    int k=0;
    while((1L<<(k+1))<=result) k++;
    int ctx2=ctx*99;
    for(int tmp=start+1; tmp<=start+k; tmp++) put_bit(tmp+ctx2,0);
    put_bit(start+k+1+ctx2,1);
    for(int i=k-1;i>=0;i--) put_bit(ctx,(int)((result>>i)&1));
}
static void finish(void){ normalize(); for(int i=0;i<8;i++) emit_digit(0); }
int main(int argc,char**argv){
  const char *s = "Hello!\n";
  if(argc>1) s=argv[1];
  int n = strlen(s);
  encode_integer(INTOFF,0,n);
  for(int i=0;i<n;i++){
    int b=(unsigned char)s[i];
    put_bit(1,0);
    if(b<128){ put_bit(8,0); encode_integer(LITSIZE,9,b); }
    else { put_bit(8,1); encode_integer(LITSIZE,9,256-b); }
  }
  finish();
  return 0;
}
